tinymce.PluginManager.requireLangPack("mc_product");tinymce.PluginManager.add("mc_product",(function(editor,url){const _=text=>editor.translate(text);const productSvg=`<svg width="24" height="24" viewBox="0 0 24 24">\n        <path d="M15.55 13c.75 0 1.41-.41 1.75-1.03l3.58-6.49c.37-.66-.11-1.48-.87-1.48H5.21l-.94-2H1v2h2l3.6 7.59-1.35 2.44C4.52 15.37 5.48 17 7 17h12v-2H7l1.1-2h7.45zM6.16 6h12.15l-2.76 5H8.53L6.16 6zM7 18c-1.1 0-1.99.9-1.99 2S5.9 22 7 22s2-.9 2-2-.9-2-2-2zm10 0c-1.1 0-1.99.9-1.99 2s.89 2 1.99 2 2-.9 2-2-.9-2-2-2z" fill="currentColor"/>\n    </svg>`;editor.ui.registry.addIcon("product",productSvg);const showDialog=()=>{editor.windowManager.openUrl({title:_("mc_product Title")||"Insérer un produit",url:typeof baseadmin!=="undefined"?"/"+baseadmin+"/plugins/mc_product/product.php":url+"/product.php",width:800,height:550})};editor.ui.registry.addButton("mc_product",{icon:"product",tooltip:_("mc_product Tooltip")||"Lien vers un produit",onAction:showDialog,onSetup:api=>{const nodeChangeHandler=e=>api.setEnabled(e.element.nodeName!=="IMG");editor.on("NodeChange",nodeChangeHandler);return()=>editor.off("NodeChange",nodeChangeHandler)}});editor.ui.registry.addMenuItem("mc_product",{icon:"product",text:_("mc_product Title")||"Produit",onAction:showDialog});return{getMetadata:()=>({name:"Magix CMS Product",author:"Gerits Aurelien",version:"2.0.0"})}}));